export function initialize(dotNetRef) {
    function reportWidth() {
        dotNetRef.invokeMethodAsync('OnResize', window.innerWidth);
    }

    reportWidth();

    window.__screenSizeHandler = reportWidth;
    window.addEventListener('resize', reportWidth);
}

export function dispose() {
    if (window.__screenSizeHandler) {
        window.removeEventListener('resize', window.__screenSizeHandler);
        delete window.__screenSizeHandler;
    }
}

